{
    uint32_t gpioA      = 0xFFFFFFFFU;
    uint32_t gpioB      = 0xFFFFFFFFU;
    uint32_t gpioC      = 0xFFFFFFFFU;
    uint32_t gpioD      = 0xFFFFFFFFU;
    uint32_t gpioF      = 0xFFFFFFFFU;
    uint32_t gpioG      = 0xFFFFFFFFU;
    uint32_t gpioH      = 0xFFFFFFFFU;

    //
    //  Read Pin Count
    //
    uint32_t pinCount    = \
        (HWREG(DEVCFG_BASE + SYSCTL_O_PARTIDL) & SYSCTL_PARTIDL_PIN_COUNT_M) >> SYSCTL_PARTIDL_PIN_COUNT_S;

    //
    //  Get pull up enable settings for the pin count
    //
    switch(pinCount)
    {
        case PIN_COUNT_100:
                gpioA = F29H85x_100_PIN_QFP_GPA;
                gpioB = F29H85x_100_PIN_QFP_GPB;
                gpioC = F29H85x_100_PIN_QFP_GPC;
                gpioD = F29H85x_100_PIN_QFP_GPD;
                gpioF = F29H85x_100_PIN_QFP_GPF;
                gpioG = F29H85x_100_PIN_QFP_GPG;
                gpioH = F29H85x_100_PIN_QFP_GPH;
                break;

        case PIN_COUNT_144:
                gpioA = F29H85x_144_PIN_QFP_GPA;
                gpioB = F29H85x_144_PIN_QFP_GPB;
                gpioC = F29H85x_144_PIN_QFP_GPC;
                gpioD = F29H85x_144_PIN_QFP_GPD;
                gpioF = F29H85x_144_PIN_QFP_GPF;
                gpioG = F29H85x_144_PIN_QFP_GPG;
                gpioH = F29H85x_144_PIN_QFP_GPH;
                break;

        case PIN_COUNT_176:
                gpioA = F29H85x_176_PIN_QFP_GPA;
                gpioB = F29H85x_176_PIN_QFP_GPB;
                gpioC = F29H85x_176_PIN_QFP_GPC;
                gpioD = F29H85x_176_PIN_QFP_GPD;
                gpioF = F29H85x_176_PIN_QFP_GPF;
                gpioG = F29H85x_176_PIN_QFP_GPG;
                gpioH = F29H85x_176_PIN_QFP_GPH;
                break;

        default:
        case PIN_COUNT_256:
                gpioA = F29H85x_256_PIN_BGA_GPA;
                gpioB = F29H85x_256_PIN_BGA_GPB;
                gpioC = F29H85x_256_PIN_BGA_GPC;
                gpioD = F29H85x_256_PIN_BGA_GPD;
                gpioF = F29H85x_256_PIN_BGA_GPF;
                gpioG = F29H85x_256_PIN_BGA_GPG;
                gpioH = F29H85x_256_PIN_BGA_GPH;
                break;
    }

    //
    //  Configure the pull up enable settings
    //
    HWREG(GPIOCTRL_BASE + GPIO_O_GPAPUD) = gpioA;
    HWREG(GPIOCTRL_BASE + GPIO_O_GPBPUD) = gpioB;
    HWREG(GPIOCTRL_BASE + GPIO_O_GPCPUD) = gpioC;
    HWREG(GPIOCTRL_BASE + GPIO_O_GPDPUD) = gpioD;
    HWREG(GPIOCTRL_BASE + GPIO_O_GPFPUD) = gpioF;
    HWREG(GPIOCTRL_BASE + GPIO_O_GPGPUD) = gpioG;
    HWREG(GPIOCTRL_BASE + GPIO_O_GPHPUD) = gpioH;
}
